(()=>{'use strict';const bindForms=()=>{if(!wpFrontendAuth.useAjax){return;}
document.querySelectorAll('.wpfa-inner-form[data-ajax="1"]').forEach(form=>{form.addEventListener('submit',e=>{e.preventDefault();submitForm(form);});});};const submitForm=(form)=>{const container=form.closest('.wpfa-form');const btn=form.querySelector('.wpfa-submit-button');const origText=btn?btn.textContent:'';clearNotices(container);if(btn){btn.disabled=true;btn.innerHTML='<span class="wpfa-spinner" aria-hidden="true"></span>'+escHtml(origText);}
jQuery.ajax({url:form.getAttribute('action')||window.location.href,method:'POST',data:jQuery(form).serialize()+'&wpfa_ajax=1',dataType:'json',}).done(response=>{if(response&&response.success){const payload=response.data||{};if(payload.redirect){window.location.href=payload.redirect;return;}
if(payload.message){showMessage(container,payload.message);}
form.reset();}else{const errors=(response&&response.data&&response.data.errors)?response.data.errors:[wpFrontendAuth.i18n.genericError];showErrors(container,errors);}}).fail(()=>{showErrors(container,[wpFrontendAuth.i18n.genericError]);}).always(()=>{if(btn){btn.disabled=false;btn.textContent=origText;}});};const clearNotices=(container)=>{container.querySelectorAll('.wpfa-errors, .wpfa-messages').forEach(el=>{el.innerHTML='';});};const getOrCreateList=(container,cls,role)=>{let list=container.querySelector('.'+cls);if(!list){list=document.createElement('ul');list.className=cls;if(role){list.setAttribute('role',role);}
container.prepend(list);}
return list;};const showErrors=(container,messages)=>{const list=getOrCreateList(container,'wpfa-errors','alert');messages.forEach(msg=>{const li=document.createElement('li');li.className='wpfa-error';li.textContent=msg;list.appendChild(li);});};const showMessage=(container,message)=>{const list=getOrCreateList(container,'wpfa-messages','status');const li=document.createElement('li');li.className='wpfa-message';li.textContent=message;list.appendChild(li);};const bindPasswordToggle=()=>{document.querySelectorAll('.wpfa-inner-form input[type="password"]').forEach(input=>{if(!input.id){return;}
const btn=document.createElement('button');btn.type='button';btn.className='wpfa-password-toggle';btn.dataset.target=input.id;btn.dataset.show=wpFrontendAuth.i18n.show;btn.dataset.hide=wpFrontendAuth.i18n.hide;btn.setAttribute('aria-pressed','false');btn.setAttribute('aria-label',wpFrontendAuth.i18n.passwordToggle);btn.textContent=btn.dataset.show;input.insertAdjacentElement('afterend',btn);});document.addEventListener('click',e=>{const btn=e.target.closest('.wpfa-password-toggle');if(!btn){return;}
const input=document.getElementById(btn.dataset.target);if(!input){return;}
const isPassword=input.type==='password';input.type=isPassword?'text':'password';btn.textContent=isPassword?btn.dataset.hide:btn.dataset.show;btn.setAttribute('aria-pressed',isPassword?'true':'false');});};const bindPasswordStrength=()=>{const pass1=document.getElementById('pass1')||document.getElementById('user_pass1');const pass2=document.getElementById('pass2')||document.getElementById('user_pass2');if(!pass1){return;}
let meter=document.getElementById('pass-strength-result');if(!meter){meter=document.createElement('div');meter.id='pass-strength-result';meter.setAttribute('aria-live','polite');pass1.closest('.wpfa-field-wrap')?.insertAdjacentElement('afterend',meter);}
const update=()=>checkStrength(pass1.value,pass2?pass2.value:'',meter);pass1.addEventListener('input',update);if(pass2){pass2.addEventListener('input',update);}};const checkStrength=(pass1,pass2,meter)=>{if(!pass1){meter.className='';meter.textContent='';meter.style.opacity='0';return;}
let strength=0;if(window.wp&&wp.passwordStrength){strength=wp.passwordStrength.meter(pass1,wp.passwordStrength.userInputBlacklist(),pass2);}else{if(pass1.length>=8)strength++;if(pass1.length>=12)strength++;if(/[A-Z]/.test(pass1)&&/[a-z]/.test(pass1))strength++;if(/[0-9]/.test(pass1))strength++;if(/[^A-Za-z0-9]/.test(pass1))strength++;if(pass2&&pass1!==pass2)strength=Math.max(0,strength-2);strength=Math.min(4,Math.max(1,Math.ceil(strength/1.25)));}
const labels=['',wpFrontendAuth.i18n.strengthVeryWeak,wpFrontendAuth.i18n.strengthWeak,wpFrontendAuth.i18n.strengthGood,wpFrontendAuth.i18n.strengthStrong,];const classes=['','short','bad','good','strong'];meter.className=classes[strength]||'short';meter.textContent=labels[strength]||'';meter.style.opacity='1';};const handleQueryMessages=()=>{const container=document.querySelector('.wpfa-form');if(!container){return;}
const params=new URLSearchParams(window.location.search);if(params.get('password')==='changed'){showMessage(container,wpFrontendAuth.i18n.msgPasswordChanged);}
if(params.has('registered')){showMessage(container,wpFrontendAuth.i18n.msgRegistered);}
if(params.has('checkemail')){showMessage(container,wpFrontendAuth.i18n.msgCheckEmail);}};const escHtml=(str)=>{const d=document.createElement('div');d.textContent=str;return d.innerHTML;};if(typeof wpFrontendAuth==='undefined'){return;}
bindForms();bindPasswordToggle();bindPasswordStrength();handleQueryMessages();})();